INSERT INTO `ps_cms_lang` (`id_cms`, `id_lang`, `id_shop`, `meta_title`, `head_seo_title`, `meta_description`, `meta_keywords`, `content`, `link_rewrite`) VALUES
(1,	1,	1,	'Dodání',	'',	'Our terms and conditions of delivery',	'conditions, delivery, delay, shipment, pack',	'<h2>Shipments and returns</h2><h3>Your pack shipment</h3><p>Packages are generally dispatched within 2 days after receipt of payment and are shipped via UPS with tracking and drop-off without signature. If you prefer delivery by UPS Extra with required signature, an additional cost will be applied, so please contact us before choosing this method. Whichever shipment choice you make, we will provide you with a link to track your package online.</p><p>Shipping fees include handling and packing fees as well as postage costs. Handling fees are fixed, whereas transport fees vary according to total weight of the shipment. We advise you to group your items in one order. We cannot group two distinct orders placed separately, and shipping fees will apply to each of them. Your package will be dispatched at your own risk, but special care is taken to protect fragile objects.<br /><br />Boxes are amply sized and your items are well-protected.</p>',	'dodani'),
(1,	2,	1,	'Dodání',	'',	'Our terms and conditions of delivery',	'conditions, delivery, delay, shipment, pack',	'<h2>Shipments and returns</h2><h3>Your pack shipment</h3><p>Packages are generally dispatched within 2 days after receipt of payment and are shipped via UPS with tracking and drop-off without signature. If you prefer delivery by UPS Extra with required signature, an additional cost will be applied, so please contact us before choosing this method. Whichever shipment choice you make, we will provide you with a link to track your package online.</p><p>Shipping fees include handling and packing fees as well as postage costs. Handling fees are fixed, whereas transport fees vary according to total weight of the shipment. We advise you to group your items in one order. We cannot group two distinct orders placed separately, and shipping fees will apply to each of them. Your package will be dispatched at your own risk, but special care is taken to protect fragile objects.<br /><br />Boxes are amply sized and your items are well-protected.</p>',	'dodani'),
(2,	1,	1,	'GDPR',	'Zpracování osobních údajů',	'',	'Zpracování osobních údajů',	'<h2>ZPRACOVÁNÍ OSOBNÍCH ÚDAJŮ DLE GDPR – PODMÍNKY SPOLEČNOSTI L.E.S. CR SPOL. S R.O.</h2>\n<p></p>\n<p>Vážení zákazníci, předkládáme Vám tyto Obecné podmínky zpracování osobních údajů dle GDPR (dále jen „Obecné podmínky“) vydané společností L.E.S. CR spol. s r.o. Okrouhlo č.p. 215,  Okrouhlo 254 01, IČ: 25657411, dále jen „LESCR“), které informují zákazníky a obchodní partnery o tom, jaké osobní údaje společnost  LESCR zpracovává o fyzických osobách získaných při prodeji zboží, poskytování služeb a e-shopech naší společnosti, při návštěvách internetových stránek provozovaných společností a kontaktech s potenciálními zákazníky, za jakým účelem a jak po jakou dobu tyto osobní údaje L.E.S. CR zpracovává, jakým třetím osobám a z jakého důvodu je předává.</p>\n<p></p>\n<p>Obecné podmínky jsou účinné od 22.5 2018 a jsou vydány v souladu s nařízením (EU) 2016/679, o ochraně fyzických osob v souvislosti se zpracováním osobních údajů („nařízení“ nebo „GDPR“) za účelem zajištění informační povinnosti naší společnosti jako správce dle čl. 13 GDPR.</p>\n<p></p>\n<p></p>\n<h2>I. Shromažďování osobních údajů</h2>\n<p>Osobním údajem je jakákoli informace, která se vztahuje k fyzické osobě, kterou je společnost LESCR schopná identifikovat. V souvislosti s prodejem zboží a poskytováním služeb společnost LESCR může shromažďovat a zpracovávat níže uvedené kategorie osobních údajů. Pro některé účely je možné zpracovávat údaje přímo na základě smlouvy, oprávněného zájmu LESCR nebo na základě zákona, a to bez souhlasu subjektu údajů, pro jiné pouze na základě souhlasu.</p>\n<p></p>\n<p><strong>1. Základní osobní identifikační údaje </strong></p>\n<p>Tyto údaje jsou nutné pro uzavření a plnění smlouvy. Jedná se zejména o akademický titul, jméno a příjmení, datum narození, popř. IČ, DIČ, adresu trvalého pobytu, kontaktní adresu, adresu sídla nebo místa podnikání, fakturační adresu, telefonní číslo, e-mailovou adresu, popř. adresu na sociální síti, čísla předložených identifikačních dokladů a popř. jejich kopie (údaje, které nejsou potřebné pro poskytování služby, jsou na kopiích dokladů začerněny). V některých případech jsou shromažďovány identifikační údaje zástupce zákazníka nebo kontaktní osoby, kterou zákazník určí.</p>\n<p></p>\n<p>V případě smluv na jednorázový prodej zboží je rozsah omezen na základní identifikační údaje. V případě smluv o jednorázovém poskytnutí služby je rozsah osobních údajů omezen na údaje, která jsou nezbytná pro poskytnutí sjednané služby. Dále jsou zpracovávány údaje o zakoupeném zboží nebo poskytnuté službě, jejich objemu a segmentu.</p>\n<p></p>\n<p><strong>2. Technické údaje</strong></p>\n<p>LESCR shromažďujeme informace, které z technických důvodů automaticky předává prohlížeč zákazníka. Jedná se o tyto údaje - typ/verzi prohlížeče, používaný operační systém, URL předchozí navštívené stránky, jméno hlavního počítače (IP adresa), časový údaj.</p>\n<p>Při ukládání jsou tyto údaje anonymizovány a nejsou ani propojovány s údaji z jiných zdrojů. IP adresa zákazníka je brzy po ukončení návštěvy našich stránek vymazána.</p>\n<p></p>\n<p></p>\n<p><strong>3. Údaje z komunikace se zákazníkem</strong></p>\n<p>Tyto údaje vznikají při komunikaci související s poskytováním zboží a služeb společností LESCR zákazníkovi. Jedná se o zápisy osobní komunikace se zákazníkem na provozovnách nebo jiném přímém kontaktu se zákazníkem, písemnou a elektronickou komunikaci se zákazníkem.</p>\n<p></p>\n<p><strong>4. Kamerové záznamy z provozoven a prostor LESCR</strong></p>\n<p>Společnost LESCR umísťuje do svých provozoven a prostor kamery z důvodu svých ochrany oprávněných zájmů. Prostory, kde jsou kamery umístěny, jsou vždy řádně a viditelně označeny upozorněním.</p>\n<p></p>\n<p><strong>5. Údaje zpracované na základě souhlasu zákazníka nebo v souladu s oprávněným zájmem společnosti</strong></p>\n<p>Zpracování těchto údajů umožňuje společnosti LESCR zlepšovat služby, zaměřit se na to, co zákazníky opravdu zajímá, a případně zákazníky informovat o nabídkách, které jsou pro ně vhodné. Ve vybraných případech je tato činnost prováděna pouze ze souhlasem zákazníka. V zájmu zkvalitnění služeb se jedná zejména o:</p>\n<p>• zlepšení kvality služeb LESCR a vývoje nových </p>\n<p>• zobrazování pouze reklam na základě zájmů konkrétního zákazníka</p>\n<p>• provádění analýz a měření s cílem zjistit, jak jsou služby LESCR používány</p>\n<p>• analýzy preferencí a zobrazování obsahu, který odpovídá individuálním potřebám zákazníka</p>\n<p>• zasílání obchodních sdělení včetně nabídky produktů a služeb třetích stran (odhlášení z přijímání obchodních sdělení je možno provést v nastavení služby, pro kterou se uživatel k odběru takovýchto sdělení zaregistroval, popřípadě emailem: obchod@lescr.cz) a obsahových newsletterů.</p>\n<p>S uvedeným využitím je zákazník oprávněn kdykoli vyjádřit nesouhlas prostřednictvím krátkého písemného sdělení, které zašle na adresu sídla LESCR- Okrouhlo 215, 254 01 p. jílové u Prahy, nebo na e-mailovou adresu: obchod@lescr.cz</p>\n<p></p>\n<p></p>\n<h2>II. Zpracovávání osobních údajů</h2>\n<p><strong>1. Údaje zpracované bez souhlasu zákazníka</strong></p>\n<p>LESCR provádí zpracování osobních údajů z důvodu plnění smluv, plnění zákonných povinností a z důvodu oprávněných zájmů. Poskytnutí osobních údajů nutných pro plnění smlouvy, plnění zákonných povinností a ochranu oprávněných zájmů je povinné. Bez poskytnutí osobních údajů k těmto účelům by nebylo možné služby poskytovat. Zpracování z důvodu plnění smlouvy a plnění zákonných povinností nelze odmítnout. </p>\n<p>LESCR zpracovává osobní údaje ručně i automatizovaně.</p>\n<p></p>\n<p><strong>2. Doba zpracování údajů</strong></p>\n<p>Osobní údaje pro tyto činnosti jsou zpracovány v rozsahu nutném pro naplnění těchto činností a po dobu nutnou k jejich dosažení nebo po dobu přímo stanovenou právními předpisy. Poté jsou osobní údaje vymazány či anonymizovány. Osobní údaje jsou pro uvedené účely uchovávány po dobu 5 let ode dne ukončení poslední smlouvy se společnosti LESCR. </p>\n<p>V případě zakoupení zboží je společnost LESCR oprávněna zpracovávat základní osobní, identifikační a kontaktní údaje zákazníka, údaje o zboží a údaje z komunikace mezi zákazníkem a LESCR po dobu 5 let ode dne uplynutí záruční doby na zboží.</p>\n<p>U zákazníků služeb poskytovaných LESCR je společnost LESCR oprávněna zpracovávat základní osobní, identifikační a kontaktní údaje zákazníka, údaje o zboží a údaje z komunikace mezi zákazníkem a LESCR po dobu 5 let ode dne ukončení poslední smlouvy se společnosti LESCR. </p>\n<p>V případě jednání mezi společností LESCR a novým zákazníkem o uzavření smlouvy, které nebylo ukončeno uzavřením smlouvy, je společnost LESCR oprávněna zpracovávat poskytnuté osobní údaje po dobu 3 měsíců od příslušného jednání.</p>\n<p>Faktury vystavené společností LESCR jsou v souladu s § 35 zákona č. 235/2004 Sb., o dani z přidané hodnoty archivována po dobu 10 let od jejich vystavení. Z důvodu nutnosti doložit právní důvod pro vystavení faktur jsou po dobu 10 let ode dne ukončení smlouvy archivovány i zákaznické smlouvy.</p>\n<p>U dlužníků si společnost LESCR ponechává osobní údaje související s dluhem ještě po dobu 10 let poté, co bylo pravomocně ukončeno jakékoli soudní či správní řízení vedeném se zákazníkem.</p>\n<p>Kamerové záznamy z provozoven LESCR a z prostor LESCR a okolí budov LESCR jsou zpracovávány po dobu 80 dnů ode dne pořízení kamerového záznamu.</p>\n<p></p>\n<p><strong>3. Zpracování bankovních údajů v souvislosti s platbou a odstoupením od kupní smlouvy </strong></p>\n<p>LESCR umožňuje platbu na dobírku nebo bankovním převodem (do budoucna platební kartou). Všechny způsoby platby jsou komplexně chráněny bezpečnostními standardy. V případě užití platební karty LESCR splňuje požadavky předepsaného standardu Payment Card Industry Data Security Standard (PCI-DSS) a vyzývá k zadání Card Security Number.</p>\n<p>V případě odstoupení od kupní smlouvy na zboží bude společnost LESCR zpracovávat údaje zákazníka o jeho bankovním spojení. Tyto poskytnuté osobní údaje bude LESCR zpracovávat pouze v nezbytném (poskytnutém) rozsahu a jen po dobu nutnou pro provedení příslušné peněžní transakce a současně k prokázání skutečnosti, že uhrazená kupní cena byla zákazníkovi vrácena na bankovní účet uvedený zákazníkem (tj. za účelem ochrany práv a právem chráněných zájmů LESCR), max. však 90 dnů. Poskytnutí těchto osobních údajů je nezbytným předpokladem pro vrácení uhrazené kupní ceny zákazníkovi bezhotovostním převodem, a jedná se tak o zpracování bez souhlasu zákazníka.</p>\n<p>Zpracování poskytnutých údajů zákazníků o bankovním spojení bude LESCR provádět sama anebo za tímto účelem pověří, v souladu se platnými a účinnými právními předpisy, jinou třetí osobu, s tím, že zpracování musí být prováděno v České republice.</p>\n<p></p>\n<p><strong>4. Zpracování osobních údajů v souvislostí s vyřizováním reklamací, popř. jiných podnětů</strong></p>\n<p>Prostřednictvím telefonní linky 603474299 nebo emailu obchod@lescr.cz může být zákazníkem uplatněna reklamace výrobku. LESCR bude zpracovávat osobní údaje za účelem vyřízení takové reklamace, a to z důvodu plnění svých smluvních a zákonných povinností. Jedná se o zpracování osobních údajů, které nevyžaduje souhlas zákazníka.  V souvislosti s vyřizováním reklamací zpracovává LESCR osobní údaje dále také pro účely ochrany svých práv a právem chráněných zájmů pro případ možného vzniku sporu z reklamace.</p>\n<p>Prostřednictvím výše uvedené telefonní linky se mohou zákazníci a další osoby obracet na LESCR se svými dotazy. Pro zodpovězení dotazů bude LESCR zpracovávat osobní údaje poskytnuté osobou, která dotaz vznesla. Takto poskytnuté osobní údaje bude LESCR zpracovávat pouze v nezbytném (poskytnutém) rozsahu a jen do doby vyřízení dotazu či požadavku, nevznikne-li potřeba zpracovávat osobní údaje pro jiný účel (například pro ochranu práv a právem chráněných zájmů společnosti LESCR). Tyto osobní údaje jsou poskytovány zákazníkem dobrovolně, jelikož bez jejich znalosti by LESCR nebyl schopen dotaz vyřídit, souhlas zákazníka proto není požadován. </p>\n<p>Zpracování poskytnutých osobních údajů bude provádět LESCR sám. Bude-li to potřebné je LESCR oprávněn předat zpracovávané osobní údaje svým dodavatelům a výrobcům ke zpracování a vyřízení dotazu či reklamace. Konkrétní dodavatel či výrobce, kterému může LESCR takto osobní údaje předat, se odvíjí vždy od výrobku, který je reklamován, příp., jehož se dotaz týká, jakož i od místa jeho zakoupení. </p>\n<p></p>\n<p><strong>5. Zpracování osobních údajů v případě vzniku škody</strong></p>\n<p>V souvislosti s prodejem výrobků nebo poskytování služeb může vzniknout zákazníkům LESCR určitá škoda (např. škoda způsobená vadným výrobkem). V takové souvislosti dochází ke zpracování osobních údajů zákazníků a dalších se škodní událostí spojených osob (např. svědků apod.), a to v rozsahu identifikačních a kontaktních osobních údajů, údajů o způsobené škodě a dalších nezbytných souvisejících údajů. Účelem zpracování osobních údajů je v tomto případě vyřešení škodní události a ochrana práv a právem chráněných zájmů LESCR pro případ možného vzniku sporu z takovéto škodní události. Od toho se odvíjí též doba zpracování osobních údajů pro tyto účely, která odpovídá době, po kterou LESCR může v této souvislosti osobní údaje potřebovat a kdy hrozí možnost vzniku sporu ohledně vzniklé škody, tj. 10 let ode dne vzniku škodní události. Za účelem vyřešení škodní události je LESCR oprávněna zpracovávané osobní údaje předat svým dodavatelům či výrobcům. </p>\n<p></p>\n<p><strong>6. Zpracovávání údajů se souhlasem zákazníka pro obchodní účely </strong></p>\n<p>Se souhlasem pro obchodní účely se zpracovávají osobní údaje zákazníka za účelem vytvoření vhodné nabídky produktů a služeb a v souvislosti s oslovením zákazníka, buď telefonicky, písemně (včetně příloh k účtu/ faktuře), prostřednictvím internetové reklamy a formou elektronické komunikace prostřednictvím kontaktních údajů nebo čísel služby. Poskytnutí souhlasu k obchodním účelům je dobrovolné a zákazník jej může kdykoli odvolat. Tento souhlas zůstává v platnosti po dobu využívání produktů a služeb LESCR a následujících 10 let poté nebo do doby, dokud jej zákazník neodvolá. Pokud zákazník svůj souhlas odvolá, není tím dotčeno zpracování jeho osobních údajů pro jiné účely a na základě jiných právních titulů.</p>\n<p>Pro obchodní účely mohou být na základě souhlasu zpracovány údaje, k jejich zpracování udělil zákazník souhlas, a to po dobu, po kterou je LESCR oprávněn tyto údaje evidovat pro účely poskytování služeb, pokud zákazník souhlas dříve neodvolá. </p>\n<p></p>\n<p></p>\n<h2>III. Sdělení osobních údajů třetím osobám</h2>\n<p></p>\n<p>Pokud je to v souvislosti s realizací objednávky, dodáním a doručením zboží nebo propagací nabídky produktů a služeb nutné, poskytuje LESCR osobní údaje zákazníka partnerským společnostem za účelem péče o zákazníky, dodání a doručení zboží prostřednictvím třetích osob zajišťující přepravu zásilek a plnění smluvních ujednání, dále také za účelem výroby a zasílání reklamních materiálů. S těmito třetími osobami jsou uzavřeny smlouvy, jejichž součástí je závazek zacházet s osobními údaji v souladu se zákonnými ustanoveními. Součástí smluv je zákaz předávat osobní údaje zákazníků LESCR dalším osobám.</p>\n<p>Dále osobní údaje LESCR předává zejména advokátům, auditorům, správě IT systémů. Každý takový subjekt, kterému jsou osobní údaje předávány, je prověřován a s každým je uzavřena smlouva o zpracování osobních údajů. Seznam zpracovatelů je na vyžádání dostupný. Všichni zpracovatelé právnickými osobami se sídlem v České republice nebo se sídlem na území státu Evropské unie.</p>\n<p></p>\n<p></p>\n<h2>IV. Technické zabezpečení osobních údajů</h2>\n<p><strong>1. Web</strong></p>\n<p>LESCR využívá pro svoje internetové stránky editor i hosting společnosti Webnode AG</p>\n<p>Gartenstrasse 3, 6304 Zug Švýcarsko. Webnode jako firma i samotný editor fungují v souladu se směrnicí GDPR.</p>\n<p></p>\n<p><strong>2. Využití sociálních pluginů</strong></p>\n<p>Webové stránky LESCR obsahují mj. sociální pluginy třetích stran, pomocí nichž mohou návštěvníci webových stránek sdílet obsah s dalšími osobami. Jedná se o:</p>\n<p>• plugin sítě Facebook, který je spravován společností Facebook Inc., 1601 South California Avenue, Palo Alto, CA 94304, USA;</p>\n<p>• plugin služby Youtube, který spravován společností YouTube, LLC 901 Cherry Ave., 94066 San Bruno, CA, USA, dceřiná společnost Google Inc., Amphitheatre Parkway, Mountain View, CA 94043;.</p>\n<p>Tyto sociální pluginy nejsou spravovány LESCR a nenese za ně odpovědnost. Žádné osobní údaje, které zákazník zadali na webové stránky LESCR nebo které jsou o zákazníkovi u LESCR uloženy, nejsou přenášeny na sociální sítě.</p>\n<p></p>\n<p><strong>3. Cookie</strong></p>\n<p>Za účelem zlepšení služeb poskytovaných zákazníkům využívají stránky LESCR soubory cookie. Osoba zákazníka není na základě informací získaných prostřednictvím cookies identifikovatelná. Soubory cookies pomáhají zejména:</p>\n<p>• ke správné funkčnosti webových stránek, aby bylo možné dokončit proces nákupu s co nejmenšími obtížemi;</p>\n<p>• při zapamatování přihlašovacích údajů zákazníků, takže je nemusí pokaždé zadávat;</p>\n<p>• při zjišťování, které stránky a funkce používají zákazníci nejčastěji;</p>\n<p>• při zjišťování, které reklamy si zákazníci nejčastěji prohlíží, aby se jim při procházení stránek nezobrazovala stále stejná reklama, případně aby se jim nezobrazovala reklama na zboží, o které nemají zájem.</p>\n<p>Jaké soubory cookie používáme:</p>\n<p>- Krátkodobé tzv. „session cookie“ které jsou pouze dočasné a zůstávají uloženy v prohlížeči zákazníka;</p>\n<p>- dlouhodobé tzv. „persistent cookie“, které zůstávají uloženy v zařízení zákazníka mnohem déle nebo dokud nejsou ručně odstraněny.</p>\n<p>Používání souborů cookie lze nastavit pomocí internetového prohlížeče zákazníka. Většina prohlížečů soubory cookie automaticky přijímá již ve výchozím nastavení. Soubory cookie lze pomocí webového prohlížeče zákazníka odmítnout nebo nastavit užívání jen některých souborů cookie. </p>\n<p>Pokud bude mít prohlížeč zákazníka použití cookies povoleno, bude LESCR vycházet z toho, že souhlasíte s využíváním standardních cookies ze strany našich webů. Seznam cookies souborů užívaných LESCR je dostupný na vyžádání.</p>\n<p></p>\n<p><strong>4. Google Analytics a Google Adwords</strong></p>\n<p>K analýze webových stránek pomocí cookie souborů používá LESCR službu Google Analytics, vyvinutou a provozovanou společností Google Inc., se sídlem Amphitheatre Parkway, Mountain View, CA 94043, USA („Google“). </p>\n<p>Analýza pomocí služby Google Analytics probíhá tak, že informace o užívání webové stránky vytvořené prostřednictvím shromážděných cookie souborů jsou přeneseny na server Google v USA a tam podrobeny příslušné analýze. V důsledku anonymizace IP-adres, která je na webových stránkách LESCR nastavena, dochází před přenosem dat na server Google v USA ze strany Google ke zkrácení IP-adresy, a to v některém z členských států EU či Evropského hospodářského prostoru. </p>\n<p>Sběru cookie souborů a jejich analýze prostřednictvím služby Google Analytics může návštěvník webové stránky zabránit jednak změnou nastavení prohlížeče.</p>\n<p>V rámci služby Google Analytics využívá LESCR i související reklamní funkce poskytované Google, jako jsou přehledy zobrazení v reklamní síti Google, rozšířené reportování anonymních demografických dat (např. věk, pohlaví, zájmy) či zobrazování reklam v obsahové síti na základě zhlédnutých produktů (tzv. remarketing), vč. služby Google AdWords sloužící k personalizaci reklamy a zlepšení zacílení reklamy a tzv. remarketingu. </p>\n<p>Personalizaci reklamy může návštěvník webových stránek LESCR vypnout či upravit prostřednictvím svého účtu Google, a to pomocí odkazu dostupného zde.</p>\n<p>Správce prohlašuje, že přijal veškerá vhodná technická a organizační opatření k zabezpečení osobních údajů. Správce prohlašuje, že k osobním údajům mají přístup pouze jím pověřené osoby.</p>\n<p></p>\n<p></p>\n<h2>V. Právo na přístup k osobním údajům</h2>\n<p>Ve vztahu k osobním údajům má zákazník zejména následující práva:</p>\n<p>• právo svůj souhlas kdykoli odvolat;</p>\n<p>• právo osobní údaje opravit či doplnit;</p>\n<p>• právo požadovat omezení zpracování;</p>\n<p>• právo vznést námitku či stížnost proti zpracování v určitých případech;</p>\n<p>• právo požadovat přenesení údajů;</p>\n<p>• právo na přístup k osobním údajům;</p>\n<p>• právo být informován o porušení zabezpečení osobních údajů v určitých případech;</p>\n<p>• právo na výmaz osobních údajů (právo být „zapomenut“) v určitých případech; a</p>\n<p>• další práva stanovená v zákoně o ochraně osobních údajů a v obecném nařízení o ochraně osobních údajů č. 2016/679 po nabytí jeho účinnosti.</p>\n<p></p>\n<p><strong>1. Právo na přístup k osobním údajům</strong></p>\n<p>Dle čl. 15 GDPR bude mít subjekt údajů právo na přístup k osobním údajům, které zahrnuje jednak právo získat od LESCR, jednak potvrzení, zda zpracovává osobní údaje, dále informace o účelech zpracování, kategoriích dotčených osobních údajů, příjemcích, kterým osobní údaje byly nebo budou zpřístupněny, plánované době zpracování, o existenci práva požadovat od správce opravu nebo výmaz osobních údajů týkajících se subjektu údajů nebo omezení jejich zpracování nebo vznést námitku proti tomuto zpracování, právu podat stížnost u dozorového úřadu, o veškerých dostupných informacích o zdroji osobních údajů, pokud nejsou získány od subjektu údajů, skutečnosti, že dochází k automatizovanému rozhodování, včetně profilování, o vhodných zárukách při předání údajů mimo EU, v případě, že nebudou nepříznivě dotčena práva a svobody jiných osob i kopii osobních údajů.</p>\n<p>V případě opakované žádosti je LESCR oprávněn účtovat za kopii osobních údajů účtovat přiměřený poplatek. Právo na potvrzení o zpracování osobních údajů a na informace bude možné uplatnit písemně na adresu sídla společnosti LESCR, nebo na provozovně LESCR.</p>\n<p></p>\n<p><strong>2. Právo na opravu nepřesných údajů</strong></p>\n<p>Zákazník má právo na opravu nepřesných osobních údajů, které o něm LESCR zpracovává. Zákazník je povinen oznamovat LESCR změny svých osobních údajů. Zároveň je zákazník povinen poskytnout součinnost, bude-li zjištěno, že osobní údaje, které o něm LESCR zpracovává, nejsou přesné. Opravu provede bez zbytečného odkladu. </p>\n<p></p>\n<p><strong>3. Právo na výmaz</strong></p>\n<p>Zákazník má právo na výmaz osobních údajů, které se ho týkají, pokud společnost LESCR neprokáže oprávněné důvody pro zpracování těchto osobních údajů. Dobrovolně udělený souhlas se zpracováním osobních údajů může zákazník kdykoli bezplatně odvolat, a to prostřednictvím zaslání emailové zprávy na adresu: obchod@lescr.cz. Odvoláním souhlasu není dotčena možnost i nadále zpracovávat osobní údaje na základě souhlasu zákazníka, který byl dán před jeho odvoláním. Odvolání souhlasu také nemá vliv na zpracování osobních údajů, které zpracovává LESCR na jiném právním základu, než je souhlas.</p>\n<p></p>\n<p><strong>4. Právo na omezení zpracování</strong></p>\n<p>Zákazník má do doby vyřešení podnětu právo na omezení zpracování osobních údajů, pokud bude popírat jejich přesnost, důvody jejich zpracování nebo pokud podá písemnou námitku proti jejich zpracování.</p>\n<p></p>\n<p><strong>5. Právo na oznámení opravy, výmazu nebo omezení zpracování</strong></p>\n<p>Dle čl. 19 GDPR má zákazník právo na oznámení v případě opravy, výmazu nebo omezení zpracování osobních údajů. </p>\n<p></p>\n<p><strong>6. Právo na přenositelnost osobních údajů</strong></p>\n<p>Dle čl. 20 GDPR má zákazník právo na přenositelnost údajů, které se ho týkají a které poskytl LESCR, ve strukturovaném, běžně používaném a strojově čitelném formátu, a právo požádat o předání těchto údajů jinému správci. V případě, že by výkonem tohoto práva mohlo dojít k nepříznivému dotčení práv a svobod třetích osob, nelze žádosti vyhovět.</p>\n<p></p>\n<p><strong>7. Právo vznést námitku proti zpracování osobních údajů</strong></p>\n<p>Zákazník je oprávněn vznést písemnou námitku proti zpracování jeho osobních údajů z důvodu oprávněného zájmu společnosti LESCR. Pokud zákazník nebude souhlasit, že občas dostane nějaké obchodní sdělení, má možnost vznést námitku proti dalšímu zpracovávání jeho osobních údajů za účelem přímého marketingu. </p>\n<p></p>\n<p><strong>8. Právo na odvolání souhlasu se zpracováním osobních údajů</strong></p>\n<p>Souhlas se zpracováním osobních údajů pro obchodní účely účinný od 25. 5. 2018 je možné kdykoliv po tomto datu odvolat. Odvolání je zapotřebí učinit výslovným, srozumitelným a určitým projevem vůle, a to na adrese sídla LESCR. nebo na e-mailovou adresu: obchod@lescr.cz.</p>\n<p></p>\n<p><strong>9. Právo obrátit se na Úřad pro ochranu osobních údajů</strong></p>\n<p>V případě jakýchkoliv rozporů nebo pochybností má zákazník má právo se obrátit na Úřad pro ochranu osobních údajů (www.uoou.cz).</p>\n<p></p>\n<p></p>\n<h2>VI. Závěrečná ustanovení</h2>\n<p>1. S těmito podmínkami souhlasíte zaškrtnutím souhlasu prostřednictvím internetového formuláře. Zaškrtnutím souhlasu potvrzujete, že jste seznámen/a s podmínkami ochrany osobních údajů a že je v celém rozsahu přijímáte.</p>\n<p></p>\n<p>2. Správce je oprávněn tyto podmínky změnit. Novou verzi podmínek ochrany osobních údajů zveřejní na svých internetových stránkách.</p>\n<p></p>\n<p>3. Správce prohlašuje, že přijal veškerá vhodná technická a organizační opatření k zabezpečení osobních údajů. Správce prohlašuje, že k osobním údajům mají přístup pouze jím pověřené osoby.</p>\n<p></p>\n<p>4. V případě jakéhokoli dotazu na ochranu osobních údajů či odvolání souhlasu s dalším zpracováním osobních údajů využijte kontaktního emailu obchod@lescr.cz  či písemně na  adrese sídla společnosti.</p>\n<p></p>\n<p>5. V této souvislosti je LESCR oprávněn požadovat, aby zákazník za účelem prověření identity vhodným způsobem prokázal totožnost, Jde o preventivní bezpečnostní opatření zamezující přístupu neoprávněných osob k osobním údajům třetích stran. </p>\n<p></p>\n<p></p>\n<p>V Okrouhle, dne 22.5.2018                                                        Ing. Viktor Janauer</p>',	'gdpr'),
(2,	2,	1,	'Právní ustanovení',	'',	'Právní ustanovení',	'Právní, ustanovení, credits',	'<h2>Legal</h2>\n<h3>Credits</h3>\n<p>Concept and production:</p>\n<p>This Online store was created using <a href=\"http://www.prestashop.com\">Prestashop Shopping Cart Software</a>,check out PrestaShop\'s <a href=\"http://www.prestashop.com/blog/en/\">ecommerce blog</a> for news and advices about selling online and running your ecommerce website.</p>',	'legal-notice'),
(3,	1,	1,	'Obchodní podmínky',	'',	'Obchodní podmínky',	'Obchodní podmínky',	'<p>L.E.S.  CR spol. s r.o.</p>\n<p></p>\n<p>se sídlem č.p. 215, Okrouhlo 254 01 identifikační číslo: 25657411</p>\n<p></p>\n<p>zapsané v obchodním rejstříku vedeném u Městského soudu v Praze, spis. značka: C 5870 pro prodej zboží prostřednictvím on-line obchodu umístěného na internetové adrese:</p>\n<p></p>\n<p>www.e-lescr.cz</p>\n<p></p>\n<h2> 1.     ÚVODNÍ USTANOVENÍ</h2>\n<p>Tyto obchodní podmínky (dále jen „obchodní podmínky“) obchodní společnosti L.E.S.  CR spol. s r.o. se sídlem č.p. 215, Okrouhlo 254 01, identifikační číslo: 25657411, zapsané v obchodním rejstříku vedeném u Městského soudu v Praze, spis. značka: C 5870  (dále jen „prodávající“) upravují v souladu s ustanovením § 1751 odst. 1 zákona č. 89/2012 Sb., občanský zákoník (dále jen „občanský zákoník“) vzájemná práva a povinnosti smluvních stran vzniklé v souvislosti nebo na základě kupní smlouvy (dále jen „kupní smlouva“) uzavírané mezi prodávajícím a jinou fyzickou osobou (dále jen „kupující“) prostřednictvím internetového obchodu prodávajícího. Internetový obchod je prodávajícím provozován na webové stránce umístněné na internetové adrese www.e-lescr.cz (dále jen „webová stránka“).</p>\n<p></p>\n<p>1.1.      Obchodní podmínky se nevztahují na případy, kdy osoba, která má v úmyslu nakoupit zboží od prodávajícího, je právnickou osobou či osobou, jež jedná při objednávání zboží v rámci své podnikatelské činnosti nebo v rámci svého samostatného výkonu povolání.</p>\n<p></p>\n<p>1.2.      Ustanovení odchylná od obchodních podmínek je možné sjednat v kupní smlouvě. Odchylná ujednání v kupní smlouvě mají přednost před ustanoveními obchodních podmínek.</p>\n<p></p>\n<p>1.3.      Ustanovení obchodních podmínek jsou nedílnou součástí kupní smlouvy. Kupní smlouva a obchodní podmínky jsou vyhotoveny v českém jazyce. Kupní smlouvu lze uzavřít v českém jazyce.</p>\n<p></p>\n<p>1.4.      Znění obchodních podmínek může prodávající měnit či doplňovat. Tímto ustanovením nejsou dotčena práva a povinnosti vzniklá po dobu účinnosti předchozího znění obchodních podmínek.</p>\n<p></p>\n<p> </p>\n<p></p>\n<h2>2.       Uživatelský účet</h2>\n<p>2.1.      Na základě registrace kupujícího provedené na webové stránce může kupující přistupovat do svého uživatelského rozhraní. Ze svého uživatelského rozhraní může kupující provádět objednávání zboží (dále jen „uživatelský účet“). Kupující může provádět objednávání zboží též bez registrace přímo z webového rozhraní obchodu.</p>\n<p></p>\n<p>2.2.      Při registraci na webové stránce a při objednávání zboží je kupující povinen uvádět správně a pravdivě všechny údaje. Údaje uvedené v uživatelském účtu je kupující při jakékoliv jejich změně povinen aktualizovat. Údaje uvedené kupujícím v uživatelském účtu a při objednávání zboží jsou prodávajícím považovány za správné.</p>\n<p></p>\n<p>2.3.      Přístup k uživatelskému účtu je zabezpečen uživatelským jménem a heslem. Kupující je povinen zachovávat mlčenlivost ohledně informací nezbytných k přístupu do jeho uživatelského účtu.</p>\n<p></p>\n<p>2.4.      Kupující není oprávněn umožnit využívání uživatelského účtu třetím osobám.</p>\n<p></p>\n<p>2.5.      Prodávající může zrušit uživatelský účet, a to zejména v případě, kdy kupující svůj uživatelský účet déle než 2 roky nevyužívá, či v případě, kdy kupující poruší své povinnosti z kupní smlouvy (včetně obchodních podmínek).</p>\n<p></p>\n<p>2.6.      Kupující bere na vědomí, že uživatelský účet nemusí být dostupný nepřetržitě, a to zejména s ohledem na nutnou údržbu hardwarového a softwarového vybavení prodávajícího, popř. nutnou údržbu hardwarového a softwarového vybavení třetích osob.</p>\n<p></p>\n<p> </p>\n<p></p>\n<h2>3.       Uzavření kupní smlouvy</h2>\n<p>3.1.      Veškerá prezentace zboží umístěná ve webovém rozhraní obchodu je informativního charakteru a prodávající není povinen uzavřít kupní smlouvu ohledně tohoto zboží. Ustanovení § 1732 odst. 2 občanského zákoníku se nepoužije.</p>\n<p></p>\n<p>3.2.      Webové rozhraní obchodu obsahuje informace o zboží, a to včetně uvedení cen jednotlivého zboží. Ceny zboží jsou uvedeny včetně daně z přidané hodnoty a všech souvisejících poplatků. Ceny zboží zůstávají v platnosti po dobu, kdy jsou zobrazovány ve webovém rozhraní obchodu. Tímto ustanovením není omezena možnost prodávajícího uzavřít kupní smlouvu za individuálně sjednaných podmínek.</p>\n<p></p>\n<p>3.3.      Webové rozhraní obchodu obsahuje také informace o nákladech spojených s balením a dodáním zboží. Informace o nákladech spojených s balením a dodáním zboží uvedené ve webovém rozhraní obchodu platí pouze v případech, kdy je zboží doručováno v rámci území České republiky.</p>\n<p></p>\n<p>3.4.      Pro objednání zboží vyplní kupující objednávkový formulář ve webovém rozhraní obchodu. Objednávkový formulář obsahuje zejména informace o:</p>\n<p></p>\n<p>3.4.1.   objednávaném zboží (objednávané zboží „vloží“ kupující do elektronického nákupního košíku webového rozhraní obchodu),</p>\n<p></p>\n<p>3.4.2.   způsobu úhrady kupní ceny zboží, údaje o požadovaném způsobu doručení objednávaného zboží a</p>\n<p></p>\n<p>3.4.3.   informace o nákladech spojených s dodáním zboží (dále společně jen jako „objednávka“).</p>\n<p></p>\n<p>3.5.      Před zasláním objednávky prodávajícímu je kupujícímu umožněno zkontrolovat a měnit údaje, které do objednávky kupující vložil, a to i s ohledem na možnost kupujícího zjišťovat a opravovat chyby vzniklé při zadávání dat do objednávky. Objednávku odešle kupující prodávajícímu kliknutím na tlačítko „Objednat“. Údaje uvedené v objednávce jsou prodávajícím považovány za správné.</p>\n<p></p>\n<p>3.6.      Odeslání objednávky se považuje za takový úkon kupujícího, který nepochybným způsobem identifikuje objednávané zboží, kupní cenu, osobu kupujícího, způsob úhrady kupní ceny, a je pro smluvní strany závazným návrhem kupní smlouvy. Podmínkou platnosti objednávky je vyplnění všech povinných údajů v objednávkovém formuláři, seznámení se s těmito obchodními podmínkami na webové stránce a potvrzení kupujícího o tom, že se s těmito obchodními podmínkami seznámil.</p>\n<p></p>\n<p>3.7.      Prodávající neprodleně po obdržení objednávky toto obdržení kupujícímu potvrdí elektronickou poštou, a to na adresu elektronické pošty kupujícího uvedenou v uživatelském rozhraní či v objednávce (dále jen „elektronická adresa kupujícího“).</p>\n<p></p>\n<p>3.8.      Prodávající je vždy oprávněn v závislosti na charakteru objednávky (množství zboží, výše kupní ceny, předpokládané náklady na dopravu) požádat kupujícího o dodatečné potvrzení objednávky (například písemně či telefonicky).</p>\n<p></p>\n<p>3.9.      Návrh kupní smlouvy ve formě objednávky má platnost 14 dnů.</p>\n<p></p>\n<p>3.10.  Smluvní vztah mezi prodávajícím a kupujícím vzniká doručením přijetí objednávky (akceptací), jež je prodávajícím zasláno kupujícímu elektronickou poštou, a to na adresu elektronické pošty kupujícího.</p>\n<p></p>\n<p>3.11.  V případě, že některý z požadavků uvedených v objednávce nemůže prodávající splnit, zašle kupujícímu na elektronickou adresu kupujícího pozměněnou nabídku s uvedením možných variant objednávky a vyžádá si stanovisko kupujícího.</p>\n<p></p>\n<p>3.12.  Pozměněná nabídka se považuje za nový návrh kupní smlouvy a kupní smlouva je v takovém případě uzavřena až akceptací kupujícího prostřednictvím elektronické pošty.  </p>\n<p></p>\n<p>3.13.  Kupující souhlasí s použitím komunikačních prostředků na dálku při uzavírání kupní smlouvy. Náklady vzniklé kupujícímu při použití komunikačních prostředků na dálku v souvislosti s uzavřením kupní smlouvy (náklady na internetové připojení, náklady na telefonní hovory) si hradí kupující sám, přičemž tyto náklady se neliší od základní sazby.</p>\n<p></p>\n<p> </p>\n<p></p>\n<h2>4.       Cena zboží a Platební podmínky</h2>\n<p>4.1.      Cenu zboží a případné náklady spojené s dodáním zboží dle kupní smlouvy může kupující uhradit prodávajícímu následujícími způsoby:</p>\n<p></p>\n<p>-          v hotovosti na dobírku v místě určeném kupujícím v objednávce</p>\n<p></p>\n<p>-           bezhotovostně bankovním převodem na účet prodávajícího č. 1382503504/0600, vedený u společnosti GE Money Bank (dále jen „účet prodávajícího“);</p>\n<p></p>\n<p>4.2.      Společně s kupní cenou je kupující povinen zaplatit prodávajícímu také náklady spojené s balením a dodáním zboží ve smluvené výši. Není-li uvedeno výslovně jinak, rozumí se dále kupní cenou i náklady spojené s dodáním zboží.</p>\n<p></p>\n<p>4.3.      Prodávající nepožaduje od kupujícího zálohu či jinou obdobnou platbu. Tímto není dotčeno ustanovení čl. 4.6obchodních podmínek ohledně povinnosti uhradit kupní cenu zboží předem.</p>\n<p></p>\n<p>4.4.      V případě platby v hotovosti či v případě platby na dobírku je kupní cena splatná při převzetí zboží. V případě bezhotovostní platby je kupní cena splatná do 14-ti dnů od uzavření kupní smlouvy.</p>\n<p></p>\n<p>4.5.      V případě bezhotovostní platby je kupující povinen uhrazovat kupní cenu zboží společně s uvedením variabilního symbolu platby. V případě bezhotovostní platby je závazek kupujícího uhradit kupní cenu splněn okamžikem připsání příslušné částky na účet prodávajícího.</p>\n<p></p>\n<p>4.6.      Prodávající je oprávněn, zejména v případě, že ze strany kupujícího nedojde k dodatečnému potvrzení objednávky (čl. 3.8), požadovat uhrazení celé kupní ceny ještě před odesláním zboží kupujícímu. Ustanovení § 2119 odst. 1 občanského zákoníku se nepoužije.</p>\n<p></p>\n<p>4.7.      Případné slevy z ceny zboží poskytnuté prodávajícím kupujícímu nelze vzájemně kombinovat.</p>\n<p></p>\n<p>4.8.      Je-li to v obchodním styku obvyklé nebo je-li tak stanoveno obecně závaznými právními předpisy, vystaví prodávající ohledně plateb prováděných na základě kupní smlouvy kupujícímu daňový doklad – fakturu. Prodávající je plátcem daně z přidané hodnoty. Daňový doklad – fakturu vystaví prodávající kupujícímu po uhrazení ceny zboží a zašle jej v elektronické podobě na elektronickou adresu kupujícího.</p>\n<p></p>\n<p>4.9.      U zboží, které není na e-shopu skladem, může dojít před dokončením obchodu k navýšení ceny pouze, jestliže se tak stane na základě navýšení nákupní ceny nového zboží od dodavatele (výrobce).  Prodávající je povinen kupujícího upozornit na tuto skutečnost ještě před vystavením  daňového dokladu a odesláním zboží.</p>\n<p></p>\n<p> </p>\n<p></p>\n<h2>5.       Odstoupení od kupní smlouvy</h2>\n<p>5.1.      Kupující bere na vědomí, že dle ustanovení § 1837 občanského zákoníku, nelze mimo jiné odstoupit od kupní smlouvy:</p>\n<p></p>\n<p>5.1.1.   o dodávce zboží, jehož cena závisí na výchylkách finančního trhu nezávisle na vůli prodávajícího a k němuž může dojít během lhůty pro odstoupení od smlouvy,</p>\n<p></p>\n<p>5.1.2.   o dodání alkoholických nápojů, jež mohou být dodány až po uplynutí třiceti dnů a jejichž cena závisí na výchylkách finančního trhu nezávislých na vůli prodávajícího,</p>\n<p></p>\n<p>5.1.3.   o dodávce zboží, které bylo upraveno podle přání kupujícího nebo pro jeho osobu</p>\n<p></p>\n<p>5.1.4.   o dodávce zboží, které podléhá rychlé zkáze, jakož i zboží, které bylo po dodání nenávratně smíseno s jiným zbožím,</p>\n<p></p>\n<p>5.1.5.    o dodávce zboží v uzavřeném obalu, které kupující z obalu vyňal a z hygienických důvodů jej není možné vrátit,</p>\n<p></p>\n<p>5.1.6.    o dodávce zvukové nebo obrazové nahrávky nebo počítačového programu, pokud porušil jejich původní obal,</p>\n<p></p>\n<p>5.1.7.   o dodávce novin, periodik nebo časopisů,</p>\n<p></p>\n<p>5.1.8.   o dodání digitálního obsahu, pokud nebyl dodán na hmotném nosiči a byl dodán s předchozím výslovným souhlasem kupujícího před uplynutím lhůty pro odstoupení od smlouvy a prodávající před uzavřením smlouvy sdělil kupujícímu, že v takovém případě nemá právo na odstoupení od smlouvy.</p>\n<p></p>\n<p>5.2.      Nejedná-li se o případ uvedený v čl. 5.1či o jiný případ, kdy nelze od kupní smlouvy odstoupit, má kupující v souladu s ustanovením § 1829 odst. 1 občanského zákoníku právo od kupní smlouvy odstoupit, a to do čtrnácti (14) dnů od převzetí zboží, přičemž v případě, že předmětem kupní smlouvy je několik druhů zboží nebo dodání několika částí, běží tato lhůta ode dne převzetí poslední dodávky zboží. Odstoupení od kupní smlouvy musí být prodávajícímu odesláno písemně poštou nebo elektronicky ve lhůtě uvedené v předchozí větě.</p>\n<p></p>\n<p>5.3.      Pro odstoupení od kupní smlouvy může kupující využit vzorový formulář poskytovaný prodávajícím, jenž tvoří přílohu obchodních podmínek. Odstoupení od kupní smlouvy může kupující zasílat mimo na adresu provozovny nebo sídla prodávajícího. Pro doručování odstoupení od smlouvy platí ustanovení čl. 11 těchto obchodních podmínek. Podnikatel potvrdí spotřebiteli bez zbytečného odkladu v textové podobě jeho přijetí.</p>\n<p></p>\n<p>5.4.      V případě odstoupení od kupní smlouvy dle čl. 5.2obchodních podmínek se kupní smlouva od počátku ruší. Zboží musí být prodávajícímu vráceno do čtrnácti (14) dnů od odstoupení od smlouvy prodávajícímu. Odstoupí-li kupující od kupní smlouvy, nese kupující náklady spojené s navrácením zboží prodávajícímu, a to i v tom případě, kdy zboží nemůže být vráceno pro svou povahu obvyklou poštovní cestou.</p>\n<p></p>\n<p>5.5.      V případě odstoupení od smlouvy dle čl. 5.2obchodních podmínek vrátí prodávající peněžní prostředky přijaté od kupujícího do čtrnácti (14) dnů od odstoupení od kupní smlouvy kupujícím, a to stejným způsobem, jakým je prodávající od kupujícího přijal. Prodávající je taktéž oprávněn vrátit plnění poskytnuté kupujícím již při vrácení zboží kupujícím či jiným způsobem, pokud s tím kupující bude souhlasit a nevzniknou tím kupujícímu další náklady. Odstoupí-li kupující od kupní smlouvy, prodávající není povinen vrátit přijaté peněžní prostředky kupujícímu dříve, než mu kupující zboží vrátí nebo prokáže, že zboží prodávajícímu odeslal.</p>\n<p></p>\n<p>5.6.      Nárok na úhradu škody vzniklé na zboží je prodávající oprávněn jednostranně započíst proti nároku kupujícího na vrácení kupní ceny.</p>\n<p></p>\n<p>5.7.      Do doby převzetí zboží kupujícím je prodávající oprávněn kdykoliv od kupní smlouvy odstoupit. V takovém případě vrátí prodávající kupujícímu kupní cenu bez zbytečného odkladu, a to bezhotovostně na účet určený kupujícím.</p>\n<p></p>\n<p>5.8.      Je-li společně se zbožím poskytnut kupujícímu dárek, je darovací smlouva mezi prodávajícím a kupujícím uzavřena s rozvazovací podmínkou, že dojde-li k odstoupení od kupní smlouvy kupujícím, pozbývá darovací smlouva ohledně takového dárku účinnosti a kupující je povinen spolu se zbožím prodávajícímu vrátit i poskytnutý dárek.</p>\n<p></p>\n<p> </p>\n<p></p>\n<h2>6.       Přeprava a dodání zboží</h2>\n<p>6.1.      V případě, že je způsob dopravy smluven na základě zvláštního požadavku kupujícího, nese kupující riziko a případné dodatečné náklady spojené s tímto způsobem dopravy.</p>\n<p></p>\n<p>6.2.      Je-li prodávající podle kupní smlouvy povinen dodat zboží na místo určené kupujícím v objednávce, je kupující povinen převzít zboží při dodání.</p>\n<p></p>\n<p>6.3.      V případě, že je z důvodů na straně kupujícího nutno zboží doručovat opakovaně nebo jiným způsobem, než bylo uvedeno v objednávce, je kupující povinen uhradit náklady spojené s opakovaným doručováním zboží, resp. náklady spojené s jiným způsobem doručení.</p>\n<p></p>\n<p>6.4.      Při převzetí zboží od přepravce je kupující povinen zkontrolovat neporušenost obalů zboží a v případě jakýchkoliv závad toto neprodleně oznámit přepravci. V případě shledání porušení obalu svědčícího o neoprávněném vniknutí do zásilky nemusí kupující zásilku od přepravce převzít.</p>\n<p></p>\n<p>6.5.     Při doručování přípravků na ochranu rostlin v době mrazů, bude prodávajcí čekat s doručením na dny s teplotou nad bodem mrazu.</p>\n<p></p>\n<p>6.6.     Prodávající má právo zvolit takovou přepravní službu, která je pro jejich transport např. přípravky na ochranu rostlin oprávněna. A to i v rozporu s přáním kupujícího.</p>\n<p></p>\n<p> </p>\n<p></p>\n<h2>7.       Práva z Vadného plnění</h2>\n<p>7.1.      Práva a povinnosti smluvních stran ohledně práv z vadného plnění se řídí příslušnými obecně závaznými předpisy (zejména ustanoveními § 1914 až 1925, § 2099 až 2117 a § 2161 až 2174 občanského zákoníku).</p>\n<p></p>\n<p>7.2.      Prodávající odpovídá kupujícímu, že zboží při převzetí nemá vady. Zejména prodávající odpovídá kupujícímu, že v době, kdy kupující zboží převzal:</p>\n<p></p>\n<p>7.2.1.   má zboží vlastnosti, které si strany ujednaly, a chybí-li ujednání, má takové vlastnosti, které prodávající nebo výrobce popsal nebo které kupující očekával s ohledem na povahu zboží a na základě reklamy jimi prováděné,</p>\n<p></p>\n<p>7.2.2.   se zboží hodí k účelu, který pro jeho použití prodávající uvádí nebo ke kterému se zboží tohoto druhu obvykle používá,</p>\n<p></p>\n<p>7.2.3.   zboží odpovídá jakostí nebo provedením smluvenému vzorku nebo předloze, byla-li jakost nebo provedení určeno podle smluveného vzorku nebo předlohy,</p>\n<p></p>\n<p>7.2.4.   je zboží v odpovídajícím množství, míře nebo hmotnosti a</p>\n<p></p>\n<p>7.2.5.   zboží vyhovuje požadavkům právních předpisů.</p>\n<p></p>\n<p>7.3.      Ustanovení uvedená v čl. 7.2 obchodních podmínek se nepoužijí u zboží prodávaného za nižší cenu na vadu, pro kterou byla nižší cena ujednána, na opotřebení zboží způsobené jeho obvyklým užíváním, u použitého zboží na vadu odpovídající míře používání nebo opotřebení, kterou zboží mělo při převzetí kupujícím, nebo vyplývá-li to z povahy zboží.</p>\n<p></p>\n<p>7.4.      Projeví-li se vada v průběhu šesti měsíců od převzetí, má se za to, že zboží bylo vadné již při převzetí.</p>\n<p></p>\n<p>7.5.      Práva z vadného plnění uplatňuje kupující u prodávajícího na adrese jeho provozovny, v níž je přijetí reklamace možné s ohledem na sortiment prodávaného zboží. Za okamžik uplatnění reklamace se považuje okamžik, kdy prodávající obdržel od kupujícího reklamované zboží.</p>\n<p></p>\n<p>7.6.      Další práva a povinnosti stran související s odpovědností prodávajícího za vady může upravit reklamační řád prodávajícího.</p>\n<p></p>\n<p> </p>\n<p></p>\n<h2>8.       Další práva a povinnosti smluvních stran</h2>\n<p>8.1.      Kupující nabývá vlastnictví ke zboží zaplacením celé kupní ceny zboží</p>\n<p></p>\n<p>8.2.      Prodávající není ve vztahu ke kupujícímu vázán žádnými kodexy chování ve smyslu ustanovení § 1826 odst. 1 písm. e) občanského zákoníku.</p>\n<p></p>\n<p>8.3.      K mimosoudnímu řešení spotřebitelských sporů z kupní smlouvy je příslušná Česká obchodní inspekce, se sídlem Štěpánská 567/15, 120 00 Praha 2, IČ: 000 20 869, internetová adresa: http://www.coi.cz</p>\n<p></p>\n<p>8.4.      Prodávající je oprávněn k prodeji zboží na základě živnostenského oprávnění. Živnostenskou kontrolu provádí v rámci své působnosti příslušný živnostenský úřad. Dozor nad oblastí ochrany osobních údajů vykonává Úřad pro ochranu osobních údajů. Česká obchodní inspekce vykonává ve vymezeném rozsahu mimo jiné dozor nad dodržováním zákona č. 634/1992 Sb., o ochraně spotřebitele, ve znění pozdějších předpisů.</p>\n<p></p>\n<p>8.5.      Kupující tímto přebírá na sebe nebezpečí změny okolností ve smyslu § 1765 odst. 2 občanského zákoníku.</p>\n<p></p>\n<p> </p>\n<p></p>\n<h2>9.       Ochrana osobních údajů</h2>\n<p>9.1.      Ochrana osobních údajů kupujícího, který je fyzickou osobou, je poskytována zákonem č. 101/2000 Sb., o ochraně osobních údajů, ve znění pozdějších předpisů.</p>\n<p></p>\n<p>9.2.      Kupující souhlasí se zpracováním těchto svých osobních údajů: jméno a příjmení, adresa bydliště, identifikační číslo, daňové identifikační číslo, adresa elektronické pošty, telefonní číslo a číslo osvědčení pro nakládání s přípravky na ochranu rostlin (dále společně vše jen jako „osobní údaje“).</p>\n<p></p>\n<p>9.3.      Kupující souhlasí se zpracováním osobních údajů prodávajícím, a to pro účely realizace práv a povinností z kupní smlouvy a pro účely vedení uživatelského účtu. Nezvolí-li kupující jinou možnost, souhlasí se zpracováním osobních údajů prodávajícím také pro účely zasílání informací a obchodních sdělení kupujícímu. Souhlas se zpracováním osobních údajů v celém rozsahu dle tohoto článku není podmínkou, která by sama o sobě znemožňovala uzavření kupní smlouvy.</p>\n<p></p>\n<p>9.4.      Kupující bere na vědomí, že je povinen své osobní údaje (při registraci, ve svém uživatelském účtu, při objednávce provedené z webového rozhraní obchodu) uvádět správně a pravdivě a že je povinen bez zbytečného odkladu informovat prodávajícího o změně ve svých osobních údajích.</p>\n<p></p>\n<p>9.5.      Zpracováním osobních údajů kupujícího může prodávající pověřit třetí osobu, jakožto zpracovatele. Kromě osob dopravujících zboží nebudou osobní údaje prodávajícím bez předchozího souhlasu kupujícího předávány třetím osobám.</p>\n<p></p>\n<p>9.6.      Osobní údaje budou zpracovávány po dobu neurčitou. Osobní údaje budou zpracovávány v elektronické podobě automatizovaným způsobem nebo v tištěné podobě neautomatizovaným způsobem.</p>\n<p></p>\n<p>9.7.      Kupující potvrzuje, že poskytnuté osobní údaje jsou přesné a že byl poučen o tom, že se jedná o dobrovolné poskytnutí osobních údajů.</p>\n<p></p>\n<p>9.8.      V případě, že by se kupující domníval, že prodávající nebo zpracovatel (čl. 9.5) provádí zpracování jeho osobních údajů, které je v rozporu s ochranou soukromého a osobního života kupujícího nebo v rozporu se zákonem, zejména jsou-li osobní údaje nepřesné s ohledem na účel jejich zpracování, může:</p>\n<p></p>\n<p>9.8.1.   požádat prodávajícího nebo zpracovatele o vysvětlení,</p>\n<p></p>\n<p>9.8.2.   požadovat, aby prodávající nebo zpracovatel odstranil takto vzniklý stav.</p>\n<p></p>\n<p>9.9.      Požádá-li kupující o informaci o zpracování svých osobních údajů, je mu prodávající povinen tuto informaci předat. Prodávající má právo za poskytnutí informace podle předchozí věty požadovat přiměřenou úhradu nepřevyšující náklady nezbytné na poskytnutí informace.</p>\n<p></p>\n<p> </p>\n<p></p>\n<h2>10.   Zasílání obchodních sdělení a ukládání cookies</h2>\n<p>10.1.  Kupující souhlasí se zasíláním informací souvisejících se zbožím, službami nebo podnikem prodávajícího na elektronickou adresu kupujícího a dále souhlasí se zasíláním obchodních sdělení prodávajícím na elektronickou adresu kupujícího.</p>\n<p></p>\n<p>10.2.  Kupující souhlasí s ukládáním tzv. cookies na jeho počítač. V případě, že je nákup na webové stránce možné provést a závazky prodávajícího z kupní smlouvy plnit, aniž by docházelo k ukládání tzv. cookies na počítač kupujícího, může kupující souhlas podle předchozí věty kdykoliv odvolat.</p>\n<p></p>\n<p> </p>\n<p></p>\n<h2>11.   Doručování</h2>\n<p>11.1.  Oznámení týkající se vztahů prodávajícího a kupujícího, zejména týkající odstoupení od kupní smlouvy, musí být doručena poštou formou doporučeného dopisu nebo elektronicky na e-mail prodejce, není-li v kupní smlouvě stanoveno jinak. Oznámení se doručují na příslušnou kontaktní adresu druhé strany a považují se za doručené a účinné okamžikem jejich dodání prostřednictvím pošty, s výjimkou oznámení o odstoupení od smlouvy učiněného kupujícím, kdy je odstoupení účinné, pokud je oznámení kupujícím ve lhůtě pro odstoupení odesláno.</p>\n<p></p>\n<p>11.2.  Za doručené se považuje i oznámení, jehož převzetí bylo adresátem odmítnuto, které nebylo vyzvednuto v úložní době, nebo které se vrátilo jako nedoručitelné.</p>\n<p></p>\n<p>11.3.  Smluvní strany můžou běžnou korespondenci vzájemně doručovat prostřednictvím elektronické pošty, a to na adresu elektronické pošty uvedenou v uživatelském účtu kupujícího či uvedenou kupujícím v objednávce, resp. na adresu uvedenou na webové stránce prodávajícího.</p>\n<p></p>\n<p> </p>\n<p></p>\n<h2>12.   Závěrečná ustanovení</h2>\n<p>12.1.  Pokud vztah založený kupní smlouvou obsahuje mezinárodní (zahraniční) prvek, pak strany sjednávají, že vztah se řídí českým právem. Tímto nejsou dotčena práva spotřebitele vyplývající z obecně závazných právních předpisů.</p>\n<p></p>\n<p>12.2.  Je-li některé ustanovení obchodních podmínek neplatné nebo neúčinné, nebo se takovým stane, namísto neplatných ustanovení nastoupí ustanovení, jehož smysl se neplatnému ustanovení co nejvíce přibližuje. Neplatností nebo neúčinností jednoho ustanovení není dotknutá platnost ostatních ustanovení. Změny a doplňky kupní smlouvy či obchodních podmínek vyžadují písemnou formu.</p>\n<p></p>\n<p>12.3.  Kupní smlouva včetně obchodních podmínek je archivována prodávajícím v elektronické podobě a není přístupná.</p>\n<p></p>\n<p>12.4.  Přílohu obchodních podmínek tvoří vzorový formulář pro odstoupení od kupní smlouvy.</p>\n<p></p>\n<p>12.5.  Kontaktní údaje prodávajícího: adresa pro doručování č.p. 215, Okrouhlo 254 01, adresa elektronické pošty obchod@lescr.cz, telefon: 313 033 170, fax: 313 033 171, GSM: 603 474 299.</p>\n<p></p>\n<p> </p>\n<p></p>\n<p>V Okrouhle dne 16.12.2019        </p>',	'obchodni-podminky'),
