(502,	NULL,	NULL,	'ABOUT_TITLE_1',	'O společnosti',	'2025-07-31 14:39:49',	'2025-07-31 14:39:49'),
(503,	NULL,	NULL,	'ABOUT_TEXT_1',	'<p>Společnost L.E.S. CR spol. s r.o. je specializovaná poradenská, marketingová a obchodní firma, která se zabývá výhradně řešením problematiky technologií v oblasti ochrany rostlin. Hlavní zaměření je směřováno především do lesního hospodářství, školkařství, částečně ovocnářství a také do oblasti okrasného zahradnictví a komunální sféry. </p>\n<p>Naším cílem je zavádění a následný rozvoj efektivních a účinných metod ochrany rostlin. Zde mají své nezastupitelné místo mimo jiných prostředků také pesticidy, feromonové atraktanty, barviva, smáčedla a ostatní pomocné přípravky a látky na ochranu lesa. </p>',	'2025-07-31 14:39:49',	'2026-01-07 10:07:40'),
(504,	NULL,	NULL,	'ABOUT_BUTTON_1',	'Více o nás',	'2025-07-31 14:39:49',	'2025-07-31 14:39:49'),
