(632,	NULL,	NULL,	'EXTRAINFO_HEADER_CONTENT',	'Vážení zákazníci, v týdnu od XX.XX. - XX.XX. bude náš e-shop z důvodu dovolené uzavřen. Objednávky vyřídíme ihned po našem návratu.',	'2025-08-15 09:47:28',	'2025-08-15 09:49:25'),
