INSERT INTO `ps_order_message_lang` (`id_order_message`, `id_lang`, `name`, `message`) VALUES
(1,	1,	'Zpoždění',	'Dobrý den,\n\nbohužel, jedna položka z vaší objednávky není momentálně skladem a z tohoto důvodu může dojít k mírnému zpoždění doručení.\nPřijměte, prosím, naši omluvu a vězte, že se situaci snažíme usilovně napravit.\n\nS pozdravem,'),
(1,	2,	'Doba doručenia',	'Dobrý deň,\n\nbohužiaľ, niektoré produkty nie sú momentálne na sklade, čo môže spôsobiť krátke oneskorenie doručenia Vašej objednávky. Prosíme, prijmite naše ospravedlnenie. Chceme Vás ubezpečiť, že Vašu objednávku vybavíme hneď ako to bude možné.\n\nS pozdravom,');
