INSERT INTO `ps_product_lang` (`id_product`, `id_shop`, `id_lang`, `description`, `description_short`, `link_rewrite`, `meta_description`, `meta_keywords`, `meta_title`, `name`, `available_now`, `available_later`, `delivery_in_stock`, `delivery_out_stock`) VALUES
(1,	1,	1,	'<p>Neselektivní kontaktní systemický vodou ředitelný herbicid určený pro hubení nežádoucí buřeně a plevelů</p>\n<p>Účinná látka: glyfosát</p>\n<p>Škodlivý činitel: jednoděložná i dvouděložná buřeň</p>\n<p>Registrovaná dávka: 1 lt–10 lt/ha</p>\n<p>Balení: 5 lt</p>\n<p></p>\n<p>Používejte přípravky na ochranu rostlin bezpečně. Před použitím si vždy přečtěte označení a informace o přípravku.</p>',	'<p>glyfosat-kontaktní systemický herbicid</p>',	'hummingbird-printed-t-shirt',	'',	'',	'',	'Roundup Klasik PRO - 5 lt',	'',	'',	'',	''),
(1,	1,	2,	'<p>Symbol of lightness and delicacy, the hummingbird evokes curiosity and joy. Studio Design\' PolyFaune collection features classic products with colorful patterns, inspired by the traditional japanese origamis. To wear with a chino or jeans. The sublimation textile printing process provides an exceptional color rendering and a color, guaranteed overtime.</p>',	'<p>Regular fit, round neckline, short sleeves. Made of extra long staple pima cotton.</p>\n<p></p>',	'hummingbird-printed-t-shirt',	'',	'',	'',	'Hummingbird printed t-shirt',	'',	'',	'',	''),
(22,	1,	1,	'<p>Symbol of lightness and delicacy, the hummingbird evokes curiosity and joy. Studio Design\' PolyFaune collection features classic products with colorful patterns, inspired by the traditional japanese origamis. To wear with a chino or jeans. The sublimation textile printing process provides an exceptional color rendering and a color, guaranteed overtime.</p>',	'<p>10-0-0-15CaO-2MgO</p>',	'hummingbird-printed-t-shirt',	'',	'',	'',	'Wuxal Sus Kalcium - 10 lt',	'Skladem',	'',	'',	''),
(22,	1,	2,	'<p>Symbol of lightness and delicacy, the hummingbird evokes curiosity and joy. Studio Design\' PolyFaune collection features classic products with colorful patterns, inspired by the traditional japanese origamis. To wear with a chino or jeans. The sublimation textile printing process provides an exceptional color rendering and a color, guaranteed overtime.</p>',	'<p>Regular fit, round neckline, short sleeves. Made of extra long staple pima cotton.</p>\n<p></p>',	'hummingbird-printed-t-shirt',	'',	'',	'',	'kópia z Hummingbird printed t-shirt',	'',	'',	'',	''),
(23,	1,	1,	'<p>Fotopast pro řešení ostrahy chat, domů, automobilů, zahrad a jiných věcí, cloudové uložiště,</p>\n<p>okamžitá notifikace mobilním telefonem, přehledně řazené fotografie, 4G konektivita, možnost fotopast ovládat přímo z cloudu zdarma, možnost zasílání krátkého videa, v té nejlepší možné kvalitě, součástí balení 32 GB SD karta</p>\n<p>Parametry: dosah PIR čidla až 18 metrů, napájení 8 x AA baterie, rozlišení fotografií až 24 MPx, zvěř lze přečíst až na 30 metrů, rozpoznání osoby až na 15 metrů v závislosti na okolních podmínkách</p>',	'<p>4G LTE, rozlišení 24 MPx, Full HD vide</p>',	'hummingbird-printed-t-shirt',	'',	'',	'',	'Fotopast FOXcam SG880-4G (+SD karta 32 GB)',	'',	'',	'',	''),
(23,	1,	2,	'<p>Symbol of lightness and delicacy, the hummingbird evokes curiosity and joy. Studio Design\' PolyFaune collection features classic products with colorful patterns, inspired by the traditional japanese origamis. To wear with a chino or jeans. The sublimation textile printing process provides an exceptional color rendering and a color, guaranteed overtime.</p>',	'<p>Regular fit, round neckline, short sleeves. Made of extra long staple pima cotton.</p>\n<p></p>',	'hummingbird-printed-t-shirt',	'',	'',	'',	'kópia z Hummingbird printed t-shirt',	'',	'',	'',	''),
(24,	1,	1,	'<p>Malá fotopast s možností baraveného pořizování záznamů v noci, pro hlídání majetku nebo monitoring revíru, součástí balení 32 GB SD karta, časovač, časosběr, přepis SD karty v případě jejího zaplnění, model 4K umí natáčet videa ve vysokém rozlišení a to včetně zvukové stopy</p>\n<p>Parametry: dosah PIR čidla 25 metrů, napájení 8 x AA baterie, rozlišení fotografií až 37 MPx.</p>',	'<p>Malá fotopast s velkým výkonem.</p>',	'hummingbird-printed-t-shirt',	'',	'',	'',	'Fotopast BOLY SG520 4K DB (+SD karta 32 GB)',	'',	'',	'',	''),
(24,	1,	2,	'<p>Symbol of lightness and delicacy, the hummingbird evokes curiosity and joy. Studio Design\' PolyFaune collection features classic products with colorful patterns, inspired by the traditional japanese origamis. To wear with a chino or jeans. The sublimation textile printing process provides an exceptional color rendering and a color, guaranteed overtime.</p>',	'<p>Regular fit, round neckline, short sleeves. Made of extra long staple pima cotton.</p>\n<p></p>',	'hummingbird-printed-t-shirt',	'',	'',	'',	'kópia z kópia z Hummingbird printed t-shirt',	'',	'',	'',	''),
(25,	1,	1,	'<p>Kompletní sada elektrického ohradníku pro ochranu pozemku, plodin, úrody před lesní a černou zvěří/divočáky. Vysoce výkonný síťový zdroj fencee power energy PE60 se silným transformátorem a výstupním napětím 12 500 V. Kvalitní modré lanko 2 ks, Ø 3mm, odpor pouze 0,17 Ω/m, délka 400 m. Mobilní bílé plastové sloupky 15 ks se zesíleným profilem umožní instalovat oplocení do výšky až 136 cm nad zemí.</p>\n<p></p>\n<p><strong>Součástí balení:</strong></p>\n<p>síťový generátor fencee power energy PE60</p>\n<p>2× modré lanko 3 mm, 400 m, měď 2 × 0,25 mm a nerez 2 × 0,25 mm</p>\n<p>15× sloupek 156 cm (nad zemí 136 cm), 11 oček</p>\n<p>1× modrobílá výstražná signální páska</p>\n<p>1× zemnící tyč 100 cm</p>\n<p></p>\n<p><strong>Součástí balení generátoru:</strong></p>\n<p>zemnící kabel 150 cm (očko-očko)</p>\n<p>připojovací kabel 100 cm (očko-srdíčko)</p>\n<p>napájecí kabel 100 cm</p>\n<p>vrut a hmoždinka pro instalaci 2 ks</p>\n<p>výstražná tabulka fencee</p>\n<p>návod k obsluze</p>',	'<p>Sada elektrického ohradníku ochrana proti černé, lesní zvěři – zdroj s vysokým napětím, 2× lanko.</p>',	'triko',	'',	'',	'',	'Fencee el.ohradník set zvěř/div.prase PE60',	'',	'',	'',	''),
(25,	1,	2,	'',	'',	'triko',	'',	'',	'',	'Triko',	'',	'',	'',	''),
(26,	1,	1,	'<p>Popis: kompletní set elektrického ohradníku sestavený na ochranu před divokou lesní zvěří. Elektrický ohradník je nejlepší variantou pro zamezení vstupu divokých zvířat, jako jsou, jeleni, daňci, divoká prasata nebo lišky na vaše pozemky a zahrady. Elektrický ohradník zabrání divokým prasatům v rozrývání vašich polí a zahrad.</p>\n<p>Kombinovaný generátor fencee power DUO PD50 s výkonem 5 J, je ideální volbou pro oplocení středně dlouhých pozemků s délkou až 40 km. Kvalitní modré lanko 3 mm v délce 400 metrů, je nejlepší volbou právě proti lesní zvěři. Díky plastovým sloupkům s pevnou špicí velmi snadno instalujete ohrazení do výšky až 136 cm nad zemí.</p>\n<p></p>\n<p>Součástí dodávky:</p>\n<p>generátor fencee power DUO PD50</p>\n<p>1× lanko ø 3 mm, nerez 2 × 0,25 mm + měď 2 × 0,25 mm - délka 400 m</p>\n<p>10× sloupek 156 cm (nad zemí 136 cm), 11× očko</p>\n<p>1× zemnící tyč 100 cm</p>\n<p></p>\n<p>Součástí balení generátoru:</p>\n<p>1× napájecí adaptér fencee DUO 14 V 1,5 m</p>\n<p>1× zemnící kabel 150 cm (očko-očko)</p>\n<p>1× připojovací kabel 100 cm (očko-srdíčko)</p>\n<p>1× kabel bateriový fencee DUO 1,7 m</p>\n<p>1× výstražná tabulka</p>\n<p>1× návod k obsluze</p>',	'<p>Set elektrického ohradníku ochrana před zvěří - jelen, divoké prase, daněk - DUO zdroj - lanko 400 m</p>',	'hummingbird-printed-t-shirt',	'',	'',	'',	'Fencee el.ohradník set jelen/daněk/div.prase PD50',	'',	'',	'',	''),
(26,	1,	2,	'<p>Symbol of lightness and delicacy, the hummingbird evokes curiosity and joy. Studio Design\' PolyFaune collection features classic products with colorful patterns, inspired by the traditional japanese origamis. To wear with a chino or jeans. The sublimation textile printing process provides an exceptional color rendering and a color, guaranteed overtime.</p>',	'<p>Regular fit, round neckline, short sleeves. Made of extra long staple pima cotton.</p>\n<p></p>',	'hummingbird-printed-t-shirt',	'',	'',	'',	'kópia z Hummingbird printed t-shirt',	'',	'',	'',	''),
(33,	1,	1,	'<p>Dámská bunda na ochranu před větrem, deštěm a chladem díky jedinečnému tepelnému zátěru ClimaProtect, uvnitř izolační fleecová podšívka, stojáček podšitý fleecem, dvoucestný zip s chráničem brady, odnímatelná kapuce se šňůrkou, dvě boční kapsy se skrytým zipem a podšívkou ze síťoviny a dvě vnitřní síťované kapsy</p>\n<p>Materiál: vnější tkanina 96% polyester a 4% elastan, vnitřní 100% polyester</p>\n<p>Barva: černá</p>\n<p>Velikost: 42D</p>',	'<p>Dámská bunda na ochranu před větrem, deštěm a chladem.</p>',	'bunda-cmp-softshellova-damska-nero-vel42',	'',	'',	'',	'Bunda CMP softshellová, dámská, nero, vel.42',	'',	'',	'',	''),
(33,	1,	2,	'',	'',	'bunda-cmp-softshellova-damska-nero-vel42',	'',	'',	'',	'Bunda CMP softshellová, dámská, nero, vel.42',	'',	'',	'',	''),
(34,	1,	1,	'<p>Přechodová bunda, prodyšný a velmi tichý materiál, zip s krytkou brady, konce rukávů s elastickým okrajem, dvě kapsy na zip, dvě otevřené vnitřní kapsy</p>\n<p>Materiál: 100% polyester</p>\n<p>Barva: zelená</p>\n<p>Velikost: S-3XL</p>',	'<p>Přechodová bunda, prodyšný a velmi tichý materiál, zip s krytkou brady.</p>',	'bunda-deerhunter-chasse-fleece-vels',	'',	'',	'',	'Bunda Deerhunter Chasse fleece, vel.S',	'',	'',	'',	''),
(34,	1,	2,	'',	'',	'bunda-deerhunter-chasse-fleece-vels',	'',	'',	'',	'Bunda Deerhunter Chasse fleece, vel.S',	'',	'',	'',	''),
(35,	1,	1,	'<p>Batoh se stoličkou s lehkým, robustním, skládacím rámem, vnější kapsy batohu ze síťoviny</p>\n<p>Materiál: 100% nylon, nerezový rám stoličky</p>\n<p>Barva: khaki</p>\n<p>Parametry: kapacita 20 lt, výška 42 x šířka 25 x hloubka 14 cm, hmotnost 1600 g</p>',	'<p>Batoh se stoličkou s lehkým skládacím rámem.</p>',	'batoh-tatonka-20-lt-se-stolickou',	'',	'',	'',	'Batoh Tatonka 20 lt, se stoličkou',	'',	'',	'',	''),
(35,	1,	2,	'',	'',	'batoh-tatonka-20-lt-se-stolickou',	'',	'',	'',	'Batoh Tatonka 20 lt, se stoličkou',	'',	'',	'',	''),
(36,	1,	1,	'',	'<p>Batoh určený do přírody</p>',	'batoh-fauna-ripa-40-zeleny',	'',	'',	'',	'Batoh Fauna Ripa 40, zelený',	'',	'',	'',	''),
(36,	1,	2,	'',	'',	'batoh-fauna-ripa-40-zeleny',	'',	'',	'',	'Batoh Fauna Ripa 40, zelený',	'',	'',	'',	''),
(37,	1,	1,	'<p>Teplá, elastická čepice s příjemně měkkou podšívkou zvyšující pohodlí při nošení</p>\n<p>Materiál: 85% polyacryl, 15% elastan</p>\n<p>Barva: tmavě zelená</p>\n<p>Velikost: univerzální</p>',	'<p>Teplá, elastická čepice</p>',	'cepice-pinewood-uplet-tmzelena',	'',	'',	'',	'Čepice Pinewood, úplet, tm.zelená',	'',	'',	'Tento produkt je určen pouze pro CZ trh.',	'Tento produkt je určen pouze pro CZ trh.'),
